                if (k == 0 || k == n - 1) {
                    return false
                }

                val prev = W[k - 1]
                val next = W[k + 1]

                // Check if neighbors are letters (not hyphens)
                if (!isLetter(prev) || !isLetter(next)) {
                    return false
                }
            }
        }
        return true
    }

    val wordCounts = HashMap<String, Int>()
    var i = 0
    val n = s.length

    while (i < n) {
        if (!isWordChar(s[i])) {
            i++
            continue
        }

        // Find the end of the maximal segment
        var j = i
        while (j < n && isWordChar(s[j])) {
            j++
        }

        val potentialWord = s.substring(i, j)

        if (isValidWord(potentialWord)) {
            wordCounts[potentialWord] = wordCounts.getOrDefault(potentialWord, 0) + 1
        }

        i = j
